package main

import (
	"bufio"
	"fmt"
	"os"
	"strconv"
	"strings"
)

func Contains(slice []int, value int) bool {
	for i := 0; i < len(slice); i++ {
		if slice[i] == value {
			return true
		}
	}

	return false
}


func lowerBound(slice []int, value int) int {
	left, right := 0, len(slice)

	for left < right {
		mid := (left + right) / 2

		if slice[mid] < value {
			left = mid + 1
		} else {
			right = mid
		}
	}

	return left
}

func MagicSearch(slice []int, value int) int {
	// _, _ = slice, value

	if Contains(slice, value) {
		lo := 0

		for i := 0; i < len(slice); i++ {
			if slice[i] == value {
				lo = i
			}
		}

		return lo
	}

	return lowerBound(slice, value)
}

func main() {
	scanner := bufio.NewScanner(os.Stdin)
	scanner.Scan()
	parts := strings.Fields(scanner.Text())
	slice := make([]int, 0, 1)
	for _, elem := range parts[1 : len(parts)-1] {
		value, _ := strconv.Atoi(elem)
		slice = append(slice, value)
	}

	scanner.Scan()
	value, _ := strconv.Atoi(scanner.Text())
	result := MagicSearch(slice, value)
	fmt.Println(result)
}
